  2146→  /**
  2147→   * Get installation history for a component
  2148→   */
  2149→  async getComponentInstallationHistory(componentId: string): Promise<ComponentInstallation[]> {
  2150→    return this.traced('getComponentInstallationHistory', async (span) => {
  2151→      span.setAttribute('component.id', componentId);
  2152→
  2153→      // Verify component exists
