  /**
   * Update train fitness status with validation.
   *
   * Valid transitions:
   * - FIT -> RESTRICTED, GROUNDED
   * - RESTRICTED -> FIT, GROUNDED
   * - GROUNDED -> RESTRICTED, FIT
   *
   * Note: Transitions from GROUNDED to FIT should typically go through RESTRICTED
   * for inspection, but this is not enforced (operational flexibility).
   */
  async updateFitnessStatus(request: FitnessStatusChangeRequest): Promise<Train> {
    return this.inTransaction('updateFitnessStatus', async (tx, span) => {
      const { trainId, newStatus, notes, changedBy } = request;

      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('fitness.newStatus', newStatus);

      const train = await tx.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      const oldStatus = train.fitnessStatus;
      span.setAttribute('fitness.oldStatus', oldStatus ?? 'null');

      // Log transition
      this.log.info(
        {
          trainId,
          trainNumber: train.trainNumber,
          oldStatus,
          newStatus,
          changedBy,
        },
        `Train fitness status change: ${oldStatus} -> ${newStatus}`
      );

      // Update with notes
      const [result] = await tx
        .update(trains)
        .set({
          fitnessStatus: newStatus,
          fitnessNotes: notes ?? train.fitnessNotes,
          updatedAt: new Date(),
        })
        .where(eq(trains.id, trainId))
        .returning();

      this.recordEvent('train.fitness_changed', {
        [MmsAttributes.TRAIN_ID]: trainId,
        [MmsAttributes.TRAIN_NUMBER]: train.trainNumber,
        'fitness.old': oldStatus ?? 'unknown',
        'fitness.new': newStatus,
      }, span);

      return result;
    });
  }

