   443→  /**
   444→   * Project PM requirements for all trains over the planning horizon
   445→   */
   446→  private async projectPMRequirements(
   447→    fleetState: FleetState,
   448→    horizonYears: number,
   449→    // eslint-disable-next-line @typescript-eslint/no-unused-vars
   450→    _fromBaselineId?: string
   451→  ): Promise<PMRequirement[]> {
   452→    const requirements: PMRequirement[] = [];
   453→    const horizonEnd = addYears(new Date(), horizonYears);
   454→
   455→    for (const train of fleetState.trains) {
   456→      const trainRules = await this.getPMRulesForFleet(train.fleetId);
   457→      const trainHistory = await this.getPMHistoryForTrain(train.id);
   458→      const dailyKm = await this.calculateDailyUtilization(train, trainHistory);
   459→
   460→      const trainProjections = await this.projectTrainPMsInternal(
   461→        train,
   462→        trainRules,
   463→        trainHistory,
   464→        horizonEnd,
   465→        dailyKm
   466→      );
   467→
   468→      requirements.push(...trainProjections);
   469→    }
   470→
   471→    return requirements;
   472→  }
