   705→  private async getPMRulesForFleet(fleetId: string): Promise<PmType[]> {
   706→    const today = format(new Date(), 'yyyy-MM-dd');
   707→
   708→    return this.db.query.pmTypes.findMany({
   709→      where: and(
   710→        eq(pmTypes.fleetId, fleetId),
   711→        eq(pmTypes.active, true),
   712→        lte(pmTypes.effectiveFrom, today),
   713→        isNull(pmTypes.effectiveTo)
   714→      ),
   715→    });
   716→  }
