     1→/**
     2→ * MMS Maximo Sync Service
     3→ *
     4→ * Implements bidirectional synchronization between MMS and IBM Maximo CMMS.
     5→ * Uses the shadow record pattern to enable offline operation and conflict resolution.
     6→ *
     7→ * Key responsibilities:
     8→ * - Create and manage shadow records for PM schedules
     9→ * - Push MMS changes to Maximo (create/update work orders)
    10→ * - Pull Maximo status changes to MMS
    11→ * - Detect and resolve conflicts
    12→ * - Validate edit operations against Maximo status locks
    13→ *
    14→ * Integration flow:
    15→ * 1. When a PM is scheduled in MMS, a shadow record is created (status: PENDING)
    16→ * 2. Sync job pushes shadow records to Maximo (creates work orders)
    17→ * 3. Maximo status changes (via polling or webhook) update shadow records
    18→ * 4. INPRG/COMP/CLOSE/CAN status locks PM in MMS (read-only)
    19→ *
    20→ * @see specs/007-integration.md Section 7.4
    21→ */
    22→
    23→import { eq, and, desc, sql, inArray, lt, isNull, or, count, type SQL } from 'drizzle-orm';
    24→import { addDays, addSeconds } from 'date-fns';
    25→import { BaseService, MmsAttributes } from '../lib/services/base';
    26→import {
    27→  maximoShadowRecords,
    28→  maximoSyncHistory,
    29→  pmSchedule,
    30→  type MaximoShadowRecord,
    31→  type PmScheduleRecord,
    32→} from '../lib/db/schema';
    33→import {
    34→  MaximoConnectionError,
    35→  NotFoundError,
    36→  ValidationError,
    37→} from '../lib/errors';
    38→import { CircuitBreaker } from '../lib/utils/resilience';
    39→import { getMaximoClient, type MaximoClient } from './maximo-client';
    40→
    41→// =============================================================================
    42→// Types
    43→// =============================================================================
    44→
    45→/** Maximo work order status values */
    46→export type MaximoWoStatus = 'WAPPR' | 'APPR' | 'INPRG' | 'COMP' | 'CLOSE' | 'CAN';
    47→
    48→/** MMS sync status values */
    49→export type SyncStatus = 'PENDING' | 'SYNCED' | 'CONFLICT' | 'ERROR';
    50→
    51→/** Sync operation type */
    52→export type SyncOperation = 'PUSH' | 'PULL' | 'CONFLICT_RESOLVE';
    53→
    54→/** MMS PM status type */
    55→export type MmsPmStatus = 'SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'CANCELLED' | 'DEFERRED';
    56→
    57→/** Status mapping from Maximo to MMS */
    58→export const MAXIMO_TO_MMS_STATUS: Record<MaximoWoStatus, MmsPmStatus> = {
    59→  WAPPR: 'SCHEDULED',
    60→  APPR: 'SCHEDULED',
    61→  INPRG: 'IN_PROGRESS',
    62→  COMP: 'COMPLETED',
    63→  CLOSE: 'COMPLETED',
    64→  CAN: 'CANCELLED',
    65→};
    66→
    67→/** Locked Maximo statuses (PM cannot be edited in MMS) */
    68→export const LOCKED_MAXIMO_STATUSES: MaximoWoStatus[] = ['INPRG', 'COMP', 'CLOSE', 'CAN'];
    69→
    70→/** Human-readable status labels */
    71→export const MAXIMO_STATUS_LABELS: Record<MaximoWoStatus, string> = {
    72→  WAPPR: 'Waiting Approval',
    73→  APPR: 'Approved',
    74→  INPRG: 'In Progress',
    75→  COMP: 'Completed',
    76→  CLOSE: 'Closed',
    77→  CAN: 'Cancelled',
    78→};
    79→
    80→/** Edit validation result */
    81→export interface EditValidationResult {
    82→  valid: boolean;
    83→  reason?: 'MAXIMO_STATUS_LOCK' | 'SYNC_CONFLICT' | 'BASELINE_LOCK' | 'NOT_FOUND';
    84→  message?: string;
    85→  maximoStatus?: string;
    86→  maximoWoNum?: string;
    87→  suggestion?: string;
    88→}
    89→
    90→/** Push sync result */
    91→export interface PushResult {
    92→  action: 'CREATED' | 'UPDATED' | 'SKIPPED' | 'CONFLICT' | 'ERROR';
    93→  woNum?: string;
    94→  reason?: string;
    95→  error?: string;
    96→}
    97→
    98→/** Pull sync result */
    99→export interface PullResult {
   100→  processed: number;
   101→  updated: number;
   102→  conflicts: number;
   103→  errors: number;
   104→  details: PullDetail[];
   105→}
   106→
   107→export interface PullDetail {
   108→  pmScheduleId: string;
   109→  maximoWoNum: string;
