  1016→  /**
  1017→   * Get sync statistics
  1018→   */
  1019→  async getSyncStats(): Promise<SyncStats> {
  1020→    return this.traced('getSyncStats', async () => {
  1021→      const stats = await this.db
  1022→        .select({
  1023→          status: maximoShadowRecords.syncStatus,
  1024→          count: count(),
  1025→        })
  1026→        .from(maximoShadowRecords)
  1027→        .groupBy(maximoShadowRecords.syncStatus);
  1028→
  1029→      const statusCounts = stats.reduce(
