  1268→  async movePm(request: MovePmRequest): Promise<PmScheduleRecord> {
  1269→    return this.inTransaction('movePm', async (tx, span) => {
  1270→      const { pmScheduleId, newTargetDate, newTrackId, reason, movedBy } = request;
  1271→
  1272→      span.setAttribute('pm.scheduleId', pmScheduleId);
  1273→      span.setAttribute('pm.newTargetDate', newTargetDate);
  1274→
  1275→      // Get existing PM with relations
