  2131→  /**
  2132→   * Find an alternative date for scheduling when service demand blocks the ideal date.
  2133→   */
  2134→  private async findAlternativeDateForServiceDemand(
  2135→    trainId: string,
  2136→    windowStart: string,
  2137→    windowEnd: string
  2138→  ): Promise<string | null> {
  2139→    const start = new Date(windowStart);
  2140→    const end = new Date(windowEnd);
  2141→
  2142→    // Try each day in the window
  2143→    for (let d = start; d <= end; d.setDate(d.getDate() + 1)) {
  2144→      const dateStr = d.toISOString().split('T')[0];
  2145→      const { canSchedule } = await this.serviceDemandService.canScheduleTrainForMaintenance(
  2146→        trainId,
  2147→        dateStr
  2148→      );
  2149→
  2150→      if (canSchedule) {
  2151→        return dateStr;
  2152→      }
  2153→    }
  2154→
  2155→    return null;
  2156→  }
